dark.customCSS:
/* --- LUMINA: PREMIUM GLASSMORPHISM --- */

/* The Glass Pane Overlay */
#sidebar, input, textarea, .bg-gray-850, #auth-container {
	background: rgba(8, 13, 33, 0.45) !important;
	backdrop-filter: blur(28px) saturate(1.5) !important;
	-webkit-backdrop-filter: blur(28px) saturate(1.5) !important;
	border: 1px solid rgba(255, 255, 255, 0.05) !important;
	border-top: 1px solid rgba(255, 255, 255, 0.15) !important; /* Premium specular highlight */
	box-shadow: 0 15px 35px -5px rgba(0,0,0,0.4) !important;
	border-radius: 16px !important;
}

/* Floating Content Cards */
.prose {
	background: linear-gradient(145deg, rgba(20, 28, 50, 0.6) 0%, rgba(10, 15, 25, 0.6) 100%) !important;
	padding: 1.5rem !important;
	border-radius: 20px !important;
	border: 1px solid rgba(255,255,255,0.06) !important;
	box-shadow: 0 10px 30px rgba(0,0,0,0.2) !important;
	backdrop-filter: blur(12px) !important;
}

/* Typography */
body, .prose {
	font-family: 'SF Pro Display', 'Inter', system-ui, sans-serif !important;
}
.prose h1, .prose h2, .prose h3 {
	background: linear-gradient(135deg, #00ffcc, #b133ff);
	-webkit-background-clip: text;
	-webkit-text-fill-color: transparent;
	font-weight: 800 !important;
	letter-spacing: -0.02em;
}
.prose code {
	background: rgba(255, 255, 255, 0.08) !important;
	border-radius: 6px;
	color: #d6e0ff !important;
}

/* Aurora Button */
button.bg-blue-500, button.bg-blue-600, .btn-primary {
	background: linear-gradient(135deg, #00ffcc, #7000ff) !important;
	color: #fff !important;
	font-weight: 700 !important;
	border: none !important;
	border-radius: 30px !important;
	box-shadow: 0 8px 20px rgba(112, 0, 255, 0.3) !important;
	transition: transform 0.3s cubic-bezier(0.34, 1.56, 0.64, 1), box-shadow 0.3s !important;
}
button.bg-blue-500:hover, button.bg-blue-600:hover, .btn-primary:hover {
	transform: translateY(-2px) scale(1.03);
	box-shadow: 0 12px 25px rgba(0, 255, 204, 0.4) !important;
}

/* Inputs Focus state */
input:focus, textarea:focus {
	background: rgba(15, 25, 45, 0.7) !important;
	border-color: #00ffcc !important;
	box-shadow: 0 0 0 3px rgba(0, 255, 204, 0.15) !important;
	outline: none !important;
}

/* Custom Selection */
::selection {
	background: rgba(0, 255, 204, 0.3) !important;
	color: #fff !important;
}

/* Liquid Scrollbar */
::-webkit-scrollbar {
	width: 6px;
}
::-webkit-scrollbar-thumb {
	background: linear-gradient(to bottom, #00ffcc, #7000ff) !important;
	border-radius: 10px;
}

dark.canvasScript:
/**
 * Title: Fluid Aurora Borealis
 * Description: High-end smooth overlapping waves simulating the Northern Lights. 
 * The mouse creates a dynamic gravitational dip in the waves. 100% Transparent background.
 */

const CONFIG = {
    ribbons: 6,
    baseAmplitude: 60,
    speed: 0.003,
    colorStart: 'rgba(0, 255, 204, 0.08)',   // Mint/Cyan
    colorEnd: 'rgba(177, 51, 255, 0.08)',    // Purple
    mouseDip: 200
};

let canvas, ctx, w, h;
let time = 0;
let mouse = { x: -5000, y: -5000 };

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    } else if (e.data.type === 'mousemove') {
        mouse.x = e.data.x; mouse.y = e.data.y;
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
}

function render() {
    if (!ctx) return;

    // Mandatory Transparency clear (No gray fog trails)
    ctx.clearRect(0, 0, w, h);

    time += CONFIG.speed;

    for (let i = 0; i < CONFIG.ribbons; i++) {
        ctx.beginPath();
        ctx.moveTo(0, h);

        let timeOffset = time + (i * 0.5);

        for (let x = 0; x <= w; x += 20) {
            // Super smooth layered sine waves
            let y = (h * 0.4) 
                  + Math.sin(x * 0.002 + timeOffset) * CONFIG.baseAmplitude 
                  + Math.sin(x * 0.005 - timeOffset * 1.5) * (CONFIG.baseAmplitude * 0.5)
                  + Math.sin(x * 0.01 + timeOffset * 2) * (CONFIG.baseAmplitude * 0.2);

            // Mouse Gravity Dip
            let dx = mouse.x - x;
            let dy = mouse.y - y;
            let dist = Math.hypot(dx, dy);
            if (dist < 400) {
                let force = (400 - dist) / 400;
                // Apply easing to the force for a natural organic bend
                force = force * force * (3 - 2 * force);
                y += force * CONFIG.mouseDip;
            }

            ctx.lineTo(x, y);
        }

        ctx.lineTo(w, h);
        ctx.closePath();

        let grad = ctx.createLinearGradient(0, 0, w, h);
        grad.addColorStop(0, CONFIG.colorStart);
        grad.addColorStop(1, CONFIG.colorEnd);

        ctx.fillStyle = grad;
        ctx.fill();
    }

    requestAnimationFrame(render);
}

